## We are implementing a stack-based Virtual Machine to execute bytecode
## generated by the VanCode compiler. The VM is designed to be simple
## and portable, easily embeddable in other Nim applications or projects
## that want to build DSL (domain-specific language) features on top
## of the VanCode framework.

import std/[strutils, tables, critbits, algorithm,
          json, options, hashes, dynlib, sysatomics]

import pkg/voodoo/extensibles
import ./chunk, ./value

when defined(hayaVmWriteStackOps):
  import pkg/kapsis/interactive/prompts

macro conditionalPlaceholder(id: static string) =
  if ExtendableProcBodies.contains(id):
    result = nnkBlockStmt.newTree(
      ident("VoodooInjectedSnippet_" & id),
      ExtendableProcBodies[id]
    )
  else:
    result = newStmtList()

type
  VMPreferences* = object
    ## Preferences for configuring the VM's behavior. These can be set when creating a new VM instance
    enableHotCodeDetection*: bool
    hotProcThreshold*: int = 10
    hotChunkThreshold*: int = 100
    hotLoopThreshold*: int = 500

  CallFrame* = tuple
    ## Represents a call frame for function/procedure calls.
    currentChunk: Chunk
    cachedOps: CachedOps
    pcIdx: int
    stackBottom: int
    script: Script

  CoroutineState* = enum
    csCreated
    csSuspended
    csRunning
    csCompleted
    csErrored

  Coroutine* {.acyclic.} = ref object
    state*: CoroutineState
    callee*: Proc
    script*: Script
    savedStack*: seq[Value]
    savedCallStack*: seq[CallFrame]
    savedPcIdx*: int
    savedChunk*: Chunk
    savedCachedOps*: CachedOps
    savedStackBottom*: int
    result*: Value

  CoroutineResultKind* = enum
    crYielded
    crCompleted
    crErrored

  CoroutineResult* = object
    case kind*: CoroutineResultKind
    of crYielded: yieldedValue*: Value
    of crCompleted: resultValue*: Value
    of crErrored: errorMsg*: string

  ArgKind = enum
    akNone, akInt, akFloat, akString

  CachedOps* = ref object
    opcodes*: seq[Opcode]
    arg1*: seq[int64]
    arg2*: seq[int64]
    flags*: seq[int16]
    byteOffsets*: seq[int]
    jumpTargets*: seq[int]

  Vm* {.acyclic.} = ref object
    ## The main VM object that holds the execution state and caches
    lvl: int
    opCache: Table[Hash, CachedOps]
    hotCounts*: Table[string, int]
    hotProcCounts*: Table[string, int]

    preferences: VMPreferences
    importedModules*: Table[string, Script]
    activeCoroutine*: Coroutine
    savedStack: seq[Value]
    savedCallStack: seq[CallFrame]
    savedPcIdx: int
    savedChunk: Chunk
    savedCo: CachedOps
    savedStackBottom: int
    savedScript: Script
    jit*: JitHooks
    pendingCallback*: Value

const
  VMInitialPreallocatedStackSize* {.intdefine.} = 64
    ## initial size of the VM's evaluation stack. this is just an optimization to avoid
    ## frequent resizing during execution of small chunks. it can grow dynamically if needed.
  VMPreallocatedStackSize* {.intdefine.} = 16
    ## number of stack slots to preallocate when growing the stack. this is just an optimization to avoid
    ## frequent resizing during execution of small chunks. it can grow dynamically if needed.

proc newVm*(): Vm =
  Vm()

proc getHotProcCount*(vm: Vm, procName: string): int =
  vm.hotProcCounts.getOrDefault(procName)

proc getHotChunkCount*(vm: Vm, chunk: Chunk): int =
  vm.hotCounts.getOrDefault($chunk)

proc newVirtualMachine*(prefs: VMPreferences): Vm =
  ## Create a new VM instance with optional preferences. If preferences are not
  ## provided, defaults will be used.
  result = VM(preferences: prefs)

proc `{}`[T](x: seq[T], i: int): ptr UncheckedArray[T] =
  result = cast[ptr UncheckedArray[T]](x[i].unsafeAddr)

proc `{}`[T](x: seq[T], i: BackwardsIndex): ptr UncheckedArray[T] =
  result = x{x.len - i.int}

proc read[T](code: ptr UncheckedArray[uint8], offset: int): T =
  result = cast[ptr T](code[offset].unsafeAddr)[]

proc push(stack: var Stack, val: Value) =
  let i = stack.len
  stack.setLen(i + 1)
  stack[i] = val
  
  # additional debug output for stack operations
  when defined(hayaVmWriteStackOps):
    display(span("push", fgCyan), span($stack))

proc pop(stack: var Stack): Value =
  # additional debug output for stack operations
  when defined(hayaVmWriteStackOps):
    display(span("pop", fgCyan), span($stack[^1]))

  result = stack[^1]
  stack.setLen(stack.len - 1)

proc peek(stack: Stack): Value =
  result = stack[^1]

template inc[T](p: ptr UncheckedArray[T], offset = 1) =
  p = cast[ptr UncheckedArray[T]](cast[int](p) + offset)

template dec[T](p: ptr UncheckedArray[T], offset = 1) =
  p = cast[ptr UncheckedArray[T]](cast[int](p) - offset)

# Bit helpers
template packFlags(a1, a2: ArgKind): int16 =
  (ord(a1) or (ord(a2) shl 2)).int16

template arg1Kind(f: int16): ArgKind = ArgKind((f and 0b11).int)
template arg2Kind(f: int16): ArgKind = ArgKind(((f shr 2) and 0b11).int)

#
# Forward declarations
#
proc parseChunk(currentChunk: Chunk): CachedOps

